const suppliers = $('MySQL: High-Risk Suppliers').all();
const prices = $('MySQL: Price Deviations').all();
const grants = $('MySQL: Pending Grant Dossiers').all();

const report = {
  generated: new Date().toISOString(),
  summary: {
    high_risk_suppliers: suppliers.length,
    price_deviations: prices.length,
    pending_grant_dossiers: grants.length
  },
  data: { suppliers, prices, grants }
};

return [{ json: report }];
